  function useS() {
    const th = useTheme();
    const dark = th.bg === "#080809" || th.card === "#0f0f12";
    const tagText = (g, muscle) => muscle ? muscleAccent(muscle, g, dark) : (dark
      ? ({
          Chest: "#ff5d84",
          Back: "#8bb8ff",
          Shoulders: "#c3bdff",
          Arms: "#ff8c5f",
          Legs: "#70f5d8",
          Cardio: "#9bd2ff",
        }[g] || gc(g))
      : ({
          Chest: "#a41435",
          Back: "#2f67c8",
          Shoulders: "#6358df",
          Arms: "#b84918",
          Legs: "#087f6d",
          Cardio: "#1d6fb5",
        }[g] || gc(g)));
    return {
      input: {
        display: "block",
        width: "100%",
        maxWidth: "100%",
        minWidth: 0,
        boxSizing: "border-box",
        background: th.input,
        border: `1px solid ${th.inputB}`,
        borderRadius: 12,
        padding: "14px 16px",
        color: th.text,
        fontSize: 16,
        fontWeight: 500,
        outline: "none",
        fontFamily: "'Outfit',sans-serif",
      },
      card: {
        background: `color-mix(in srgb, ${th.card} 50%, transparent)`,
        backdropFilter: "blur(12px)",
        WebkitBackdropFilter: "blur(12px)",
        willChange: "backdrop-filter",
        transform: "translateZ(0)",
        border: `1px solid ${th.border}`,
        borderRadius: 16,
        overflow: "hidden",
      },
      label: {
        fontSize: 11,
        color: th.muted,
        letterSpacing: "2px",
        fontWeight: 700,
      },
      tag: (g, muscle) => {
        const accent = muscle ? muscleAccent(muscle, g, dark) : gc(g);
        const text = tagText(g, muscle);
        return ({
	          display: "inline-block",
	          padding: "2px 7px",
	          borderRadius: 6,
	          fontSize: 9.5,
	          fontWeight: 800,
          boxSizing: "border-box",
          background: dark ? `${accent}30` : `${accent}22`,
          border: `1px solid ${dark ? `${accent}66` : `${text}33`}`,
          color: text,
        });
      },
    };
  }

