          <path id="tricepR" d="M128 126 Q138 156 128 180 L114 180 L108 132 Q112 122 120 120 Z" fill={fill("tricepR")} opacity={opacity("tricepR")} stroke={muscleStroke} strokeWidth="0.6" />
