  function mkCardioEx(dbId) {
    const db = DB.find((e) => e.id === dbId);
    return {
      uid: uid(),
      exId: db.id,
      name: db.name,
      muscle: db.muscle,
      group: "Cardio",
      type: "cardio",
      sets: [
        {
          i: 0,
          done: false,
          duration: 0,
          distance: 0,
          calories: 0,
          intensity: 0,
        },
      ],
    };
  }
  function getTimeGreeting() {
    const h = new Date().getHours();
    if (h >= 5 && h < 12) return "Good morning";
    if (h >= 12 && h < 17) return "Good afternoon";
    if (h >= 17 && h < 21) return "Good evening";
    return "Good night";
  }
  function progInitials(n) {
    return n
      .split(/\s+/)
      .map((w) => w[0]?.toUpperCase() || "")
      .filter(Boolean)
      .slice(0, 2)
      .join("");
  }
  const PROG_COLORS = [
    "#CC1F42",
    "#5B9CF6",
    "#a29bfe",
    "#E8612C",
    "#55efc4",
    "#74b9ff",
    "#e17055",
    "#00cec9",
    "#fdcb6e",
    "#6c5ce7",
  ];
  function progColor(n) {
    let h = 0;
    for (let i = 0; i < n.length; i++) {
      h = (h * 31 + n.charCodeAt(i)) & 0xffff;
    }
    return PROG_COLORS[h % PROG_COLORS.length];
  }
  function ProgramIcon({ name, size = 38 }) {
    const c = progColor(name);
    return (
      <div
        style={{
          width: size,
          height: size,
          borderRadius: Math.round(size * 0.28),
          background: `${c}22`,
          border: `1.5px solid ${c}55`,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          flexShrink: 0,
        }}
      >
        <span
          style={{
            fontFamily: "'Bebas Neue',sans-serif",
            fontSize: Math.round(size * 0.42),
            color: c,
            letterSpacing: 1,
            lineHeight: 1,
          }}
        >
          {progInitials(name)}
        </span>
      </div>
    );
  }

  /* ─── Storage & Auth ─────────────────────────────────────────────────────────── */
  function ls(key, def) {
    try {
      const v = localStorage.getItem(key);
      return v ? JSON.parse(v) : def;
    } catch {
      return def;
    }
  }
  function lsSet(key, val) {
    try {
      localStorage.setItem(key, JSON.stringify(val));
    } catch {}
  }
  function lsDel(key) {
    try {
      localStorage.removeItem(key);
    } catch {}
  }
  const uKey = (id, k) => `ib3-${id}-${k}`;
  function saveLocalProfile(uid, profile) {
    lsSet("ib3-profile-" + uid, profile);
  }
  function getLocalProfile(uid) {
    return ls("ib3-profile-" + uid, null);
  }

  // Resize a base64 image to max 120x120 so it fits in Firestore (<20KB)
  function resizeImage(dataUrl, maxSize = 120) {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(maxSize / img.width, maxSize / img.height, 1);
        const w = Math.round(img.width * scale);
        const h = Math.round(img.height * scale);
        const canvas = document.createElement("canvas");
        canvas.width = w;
        canvas.height = h;
        canvas.getContext("2d").drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL("image/jpeg", 0.75));
      };
      img.onerror = () => resolve(dataUrl);
      img.src = dataUrl;
    });
  }

  /* ─── Firestore helpers ──────────────────────────────────────────────────────── */
  // strip() removes undefined values — Firestore rejects any field that is undefined
  function strip(obj) {
    return JSON.parse(
      JSON.stringify(obj, (_k, v) => (v === undefined ? null : v))
    );
  }

  async function fsGetPrograms(uid) {
    try {
      const snap = await getDoc(doc(fbDb, "users", uid, "data", "programs"));
      if (!snap.exists()) return [];        // doc doesn't exist = empty
      return snap.data().list || [];        // exists but no list = empty
    } catch (e) {
      if (e?.code === "permission-denied") {
        console.warn("fsGetPrograms: permission denied for uid", uid, "— Firestore rule needed: allow coach read on users/{uid}/data/programs");
      } else {
        console.error("fsGetPrograms:", e.code, e.message);
      }
      return null;                          // null = read failed (rules or network)
    }
  }
  async function fsSavePrograms(uid, list) {
    try {
      await setDoc(doc(fbDb, "users", uid, "data", "programs"), {
        list: strip(list),
      });
    } catch (e) {
      console.error("fsSavePrograms:", e.code, e.message);
    }
  }
  async function fsGetSessions(uid) {
    try {
      const snap = await getDocs(collection(fbDb, "users", uid, "sessions"));
      const docs = snap.docs.map((d) => d.data());
      return docs.sort((a, b) => (b.startTime || 0) - (a.startTime || 0));
    } catch (e) {
      console.error("fsGetSessions:", e.code, e.message);
      return [];
    }
  }
  async function fsAddSession(uid, session) {
    try {
      const clean = strip(session);
      await setDoc(
        doc(fbDb, "users", uid, "sessions", String(session.id)),
        clean
      );
      return true;
    } catch (e) {
      console.error("fsAddSession FAILED:", e.code, e.message);
      return false;
    }
  }
  async function fsUpdateSession(uid, session) {
    try {
      const clean = strip(session);
      await setDoc(
        doc(fbDb, "users", uid, "sessions", String(session.id)),
        clean,
        { merge: true }
      );
      return true;
    } catch (e) {
      console.error("fsUpdateSession FAILED:", e.code, e.message);
      return false;
    }
  }
  async function fsDeleteSession(uid, sessionId) {
    try {
      await deleteDoc(doc(fbDb, "users", uid, "sessions", String(sessionId)));
      return true;
    } catch (e) {
      console.error("fsDeleteSession FAILED:", e.code, e.message);
      return false;
    }
  }

  /* ─── Sharing / Invitations ─────────────────────────────────────────────────── */
  async function fsSendInvitation(fromUid, fromName, fromEmail, toEmail, fromPhotoURL) {
    try {
      await addDoc(collection(fbDb, "invitations"), {
        fromUid,
        fromName,
        fromEmail: fromEmail.toLowerCase().trim(),
        fromPhotoURL: fromPhotoURL || null,
        toEmail: toEmail.toLowerCase().trim(),
        status: "pending",
        createdAt: serverTimestamp(),
      });
      // Try to find the recipient's UID via publicProfiles to push a notification
      try {
        const q = query(collection(fbDb, "publicProfiles"), where("email", "==", toEmail.toLowerCase().trim()));
        const snap = await getDocs(q);
        if (!snap.empty) {
          const toUid = snap.docs[0].id;
          fsPushNotification(toUid, {
            type: "friend_request",
            fromUid,
            name: fromName,
            photoURL: fromPhotoURL || null,
            text: `${fromName} sent you a friend request`,
          });
        }
      } catch (_) { /* notification is best-effort */ }
      return { ok: true };
    } catch (e) {
      console.error("fsSendInvitation:", e);
      return { ok: false, error: e.message };
    }
  }
  // Push a notification to a user's top-level notifications collection
  async function fsPushNotification(toUid, notif) {
    try {
      await addDoc(collection(fbDb, "notifications"), {
        toUid,
        ...notif,
        ts: Date.now(),
        read: false,
      });
      return true;
    } catch {
      return false;
    }
  }

  async function fsShareProgram(fromUser, toFriend, program) {
    try {
      const docRef = await addDoc(collection(fbDb, "sharedPrograms"), {
        fromUid: fromUser.id,
        fromName: fromUser.name,
        fromPhotoURL: fromUser.photoURL || null,
        toUid: toFriend.uid,
        toName: toFriend.name,
        program: {
          id: program?.id || uid(),
          name: program?.name || "Workout",
          exs: Array.isArray(program?.exs) ? program.exs : [],
        },
        ts: Date.now(),
      });
      fsPushNotification(toFriend.uid, {
        type: "program_shared",
        fromUid: fromUser.id,
        name: fromUser.name,
        photoURL: fromUser.photoURL || null,
        text: `${fromUser.name} shared a workout program with you: ${program?.name || "Workout"}`,
        programId: docRef.id,
      });
      return { ok: true, id: docRef.id };
    } catch {
      return { ok: false };
    }
  }

  function fsListenSharedWithMe(uid, cb) {
    const q = query(collection(fbDb, "sharedPrograms"), where("toUid", "==", uid));
    return onSnapshot(q, snap => cb(snap.docs.map(d => ({ id: d.id, ...d.data() }))), () => cb([]));
  }

  function fsListenSharedByMe(uid, cb) {
    const q = query(collection(fbDb, "sharedPrograms"), where("fromUid", "==", uid));
    return onSnapshot(q, snap => cb(snap.docs.map(d => ({ id: d.id, ...d.data() }))), () => cb([]));
  }

  async function fsAcceptInvitation(inviteId, invite, currentUser) {
    try {
      await updateDoc(doc(fbDb, "invitations", inviteId), { status: "accepted" });
      const now = serverTimestamp();
      await setDoc(doc(fbDb, "users", currentUser.id, "friends", invite.fromUid), {
        uid: invite.fromUid, name: invite.fromName,
        email: invite.fromEmail, photoURL: invite.fromPhotoURL || null, since: now,
      });
      await setDoc(doc(fbDb, "users", invite.fromUid, "friends", currentUser.id), {
        uid: currentUser.id, name: currentUser.name,
        email: currentUser.email, photoURL: currentUser.photoURL || null, since: now,
      });
      // Notify the original sender that their friend request was accepted
      fsPushNotification(invite.fromUid, {
        type: "friend_accepted",
        fromUid: currentUser.id,
        name: currentUser.name,
        photoURL: currentUser.photoURL || null,
        text: `${currentUser.name} accepted your friend request`,
      });
      return true;
    } catch (e) {
      console.error("fsAcceptInvitation:", e);
      return false;
    }
  }
  async function fsDeclineInvitation(inviteId) {
    try {
      await updateDoc(doc(fbDb, "invitations", inviteId), { status: "declined" });
      return true;
    } catch (e) {
      console.error("fsDeclineInvitation:", e);
      return false;
    }
  }
  async function fsRemoveFriend(uid, friendUid) {
    try {
      await deleteDoc(doc(fbDb, "users", uid, "friends", friendUid));
      return true;
    } catch (e) {
      console.error("fsRemoveFriend:", e);
      return false;
    }
  }

  /* ─── Competition invitations ────────────────────────────────────────────────── */
  // Stored at: competitions/{id}
  // status: "pending" → "active" (immediately after accepted) → "finished"
  async function fsSendCompeteInvite(fromUid, fromName, toUid, toName) {
    try {
      // Block duplicate invites in either direction: if an active or pending
      // competition already exists between these two users, do not create a new one.
      // Otherwise both sides keep generating counter-invites that never resolve.
      const [s1, s2] = await Promise.all([
        getDocs(query(collection(fbDb, "competitions"), where("fromUid","==",fromUid), where("toUid","==",toUid))),
        getDocs(query(collection(fbDb, "competitions"), where("fromUid","==",toUid),   where("toUid","==",fromUid))),
      ]);
      const existing = [...s1.docs, ...s2.docs].find(d => {
        const st = d.data()?.status;
        return st === "pending" || st === "active";
      });
      if (existing) return { ok: false, reason: "exists", id: existing.id };

      const ref = await addDoc(collection(fbDb, "competitions"), {
        fromUid, fromName, toUid, toName,
        status: "pending",
        createdAt: serverTimestamp(),
        acceptedAt: null,
        startAt: null,
        endAt: null,
      });
      // Notify recipient of competition challenge
      fsPushNotification(toUid, {
        type: "compete_invite",
        fromUid, name: fromName,
        text: `${fromName} challenged you to a 7-day competition`,
      });
      return { ok: true, id: ref.id };
    } catch (e) {
      console.error("fsSendCompeteInvite:", e);
      return { ok: false };
    }
  }
  async function fsAcceptCompeteInvite(compId, acceptorName) {
    try {
      const compSnap = await getDoc(doc(fbDb, "competitions", compId));
      const compData = compSnap.exists() ? compSnap.data() : null;
      const now = Date.now();
      const startAt = now;
      const endAt   = startAt + 7 * 24 * 60 * 60 * 1000;
      await updateDoc(doc(fbDb, "competitions", compId), {
        status: "active",
        acceptedAt: serverTimestamp(),
        startAt,
        endAt,
      });
      // Notify the challenger that their competition was accepted
      if (compData?.fromUid) {
        fsPushNotification(compData.fromUid, {
          type: "compete_accepted",
          fromUid: compData.toUid,
          name: acceptorName || compData.toName || "Your friend",
          text: `${acceptorName || compData.toName || "Your friend"} accepted your competition challenge`,
        });
      }
      return true;
    } catch (e) {
      console.error("fsAcceptCompeteInvite:", e);
      return false;
    }
  }
  async function fsFinalizeCompetitionResult(comp, fromSessions, toSessions, finalizerUid) {
    if (!comp?.id || !comp?.fromUid || !comp?.toUid) return { ok:false };
    try {
      const fromScore = competitionScore(fromSessions, comp);
      const toScore = competitionScore(toSessions, comp);
      const winnerUid = competitionWinnerUid(comp, fromScore, toScore);
      const isTie = !winnerUid;
      const now = Date.now();
      const winnerName = winnerUid === comp.fromUid
        ? (comp.fromName || "User")
        : winnerUid === comp.toUid
        ? (comp.toName || "Friend")
        : "";
      const payload = {
        status: "finished",
        finalizedAt: msValue(comp.finalizedAt) || now,
        resultPostedAt: msValue(comp.resultPostedAt) || now,
        finalizedBy: finalizerUid || null,
        fromScore,
        toScore,
        winnerUid: winnerUid || null,
        winnerName,
        isTie,
        result: {
          fromUid: comp.fromUid,
          toUid: comp.toUid,
          fromName: comp.fromName || "User",
          toName: comp.toName || "Friend",
          fromScore,
          toScore,
          winnerUid: winnerUid || null,
          winnerName,
          isTie,
        },
      };
      await setDoc(doc(fbDb, "competitions", comp.id), strip(payload), { merge:true });
      if (!comp.resultNotifiedAt) {
        const base = {
          type: "competition_result",
          compId: comp.id,
          fromUid: finalizerUid || winnerUid || comp.fromUid,
          name: winnerName || "Competition",
          winnerUid: winnerUid || null,
          winnerName,
          fromScore,
          toScore,
          isTie,
          text: isTie
            ? "Your 7-day competition ended in a tie"
            : `${winnerName} won the 7-day competition`,
        };
        fsPushNotification(comp.fromUid, base);
        fsPushNotification(comp.toUid, base);
        setDoc(doc(fbDb, "competitions", comp.id), { resultNotifiedAt: now }, { merge:true }).catch(() => {});
      }
      return { ok:true, ...payload };
    } catch (e) {
      console.error("fsFinalizeCompetitionResult:", e?.code, e?.message || e);
      return { ok:false, error:e };
    }
  }
  async function fsDeclineCompeteInvite(compId) {
    try {
      await updateDoc(doc(fbDb, "competitions", compId), { status: "declined" });
      return true;
    } catch {
      return false;
    }
  }
  async function fsWithdrawCompeteInvite(compId) {
    try {
      await deleteDoc(doc(fbDb, "competitions", compId));
      return true;
    } catch (e) {
      console.error("fsWithdrawCompeteInvite:", e);
      return false;
    }
  }
  function fsListenCompetitions(uid, cb) {
    // Listen for competitions where user is either challenger or challenged
    const q1 = query(collection(fbDb, "competitions"), where("fromUid", "==", uid));
    const q2 = query(collection(fbDb, "competitions"), where("toUid",   "==", uid));
    let data1 = [], data2 = [];
    const merge = () => cb([...data1, ...data2]);
    const unsub1 = onSnapshot(q1, s => { data1 = s.docs.map(d=>({id:d.id,...d.data()})); merge(); });
    const unsub2 = onSnapshot(q2, s => { data2 = s.docs.map(d=>({id:d.id,...d.data()})); merge(); });
    return () => { unsub1(); unsub2(); };
  }

  /* ─── Session reactions (stars) ─────────────────────────────────────────────── */
  // Stored at: users/{ownerUid}/sessions/{sessionId}/reactions/{reactorUid}
  async function fsToggleStar(ownerUid, sessionId, reactorUid, reactorName, sessionName) {
    const subRef = doc(fbDb, "users", ownerUid, "sessions", String(sessionId), "reactions", reactorUid);
    const topRef = doc(fbDb, "reactions", `${ownerUid}_${sessionId}_${reactorUid}`);
    try {
      const snap = await getDoc(subRef);
      if (snap.exists()) {
        await deleteDoc(subRef);
        await deleteDoc(topRef);
        return false;
      } else {
        const payload = { uid: reactorUid, name: reactorName, ownerUid, sessionId: String(sessionId), sessionName: sessionName || "Workout", type: "star", ts: Date.now() };
        await setDoc(subRef, payload);
        await setDoc(topRef, payload);
        return true;
      }
    } catch (e) {
      console.error("fsToggleStar:", e);
      return null;
    }
  }
  async function fsGetReactions(ownerUid, sessionId) {
    try {
      const snap = await getDocs(collection(fbDb, "users", ownerUid, "sessions", String(sessionId), "reactions"));
      return snap.docs.map(d => d.data());
    } catch {
      return [];
    }
  }

  // Comments stored at: comments/{postId}/messages/{messageId}
  // postId = `session_${ownerUid}_${sessionId}` or `program_${sharedProgId}`
  async function fsPostComment(postId, authorUid, authorName, authorPhotoURL, text, ownerUid, contextName) {
    try {
      const ref = await addDoc(collection(fbDb, "comments", postId, "messages"), {
        authorUid, authorName, authorPhotoURL: authorPhotoURL || null,
        text: text.trim(), ts: Date.now(),
      });
      // Notify post owner (skip self-comment). Include enough identifiers so a tap
      // on the notification can deep-link straight to the post in the feed.
      if (ownerUid && ownerUid !== authorUid) {
        const isSession = String(postId).startsWith("session_");
        // postId formats: `session_${ownerUid}_${sessionId}` | `program_${spId}`
        const sessionId = isSession ? String(postId).split("_").slice(2).join("_") : null;
        const spId      = !isSession ? String(postId).replace(/^program_/, "") : null;
        fsPushNotification(ownerUid, {
          type: isSession ? "session_comment" : "program_comment",
          fromUid: authorUid,
          name: authorName,
          photoURL: authorPhotoURL || null,
          postId,
          ownerUid,
          sessionId, sessionName: isSession ? contextName : null,
          spId,      programName: !isSession ? contextName : null,
          text: isSession
            ? `${authorName} commented on your workout${contextName ? ` "${contextName}"` : ""}`
            : `${authorName} commented on your program${contextName ? ` "${contextName}"` : ""}`,
        });
      }
      return { ok: true, id: ref.id };
    } catch (e) { console.warn("fsPostComment:", e.code); return { ok: false }; }
  }

  function fsListenComments(postId, cb) {
    return onSnapshot(
      collection(fbDb, "comments", postId, "messages"),
      snap => cb(snap.docs.map(d => ({ id: d.id, ...d.data() })).sort((a,b) => a.ts - b.ts)),
      err => { console.warn("fsListenComments:", err.code, err.message); cb([], err); }
    );
  }

  async function fsToggleCommentStar(postId, uid, messageId) {
    if (!postId || !uid || !messageId) return { ok:false };
    const ref = doc(fbDb, "comments", String(postId), "messages", String(messageId));
    try {
      const snap = await getDoc(ref);
      const reactions = snap.exists() ? (snap.data().reactions || {}) : {};
      const field = `reactions.${uid}`;
      if (reactions?.[uid] === "star") {
        await updateDoc(ref, { [field]: deleteField() });
        return { ok:true, starred:false };
      }
      await updateDoc(ref, { [field]: "star" });
      return { ok:true, starred:true };
    } catch (e) {
      console.warn("fsToggleCommentStar:", e.code, e.message);
      return { ok:false, error:e };
    }
  }

