  function stravaRedirectUri() {
    if (typeof window === "undefined") return "";
    return `${window.location.origin}${window.location.pathname}`;
  }
  function stravaStateKey(uid) {
    return uKey(uid, "stravaOAuthState");
  }
  function stravaConnectionKey(uid) {
    return uKey(uid, "stravaConnection");
  }
  function stravaRandomState() {
    const arr = new Uint32Array(2);
    if (typeof crypto !== "undefined" && crypto.getRandomValues) {
      crypto.getRandomValues(arr);
      return `${arr[0].toString(36)}${arr[1].toString(36)}`;
    }
    return `${Date.now().toString(36)}${Math.random().toString(36).slice(2)}`;
  }
  function stravaAuthorizeUrl(uid) {
    const state = `${uid}.${stravaRandomState()}`;
    lsSet(stravaStateKey(uid), state);
    const params = new URLSearchParams({
      client_id: STRAVA_CLIENT_ID,
      redirect_uri: stravaRedirectUri(),
      response_type: "code",
      approval_prompt: "auto",
      scope: STRAVA_SCOPE,
      state,
    });
    return `https://www.strava.com/oauth/authorize?${params.toString()}`;
  }
  async function callStravaFunction(name, payload = {}) {
    const callable = httpsCallable(fbFunctions, name);
    const result = await callable(payload);
    return result?.data || {};
  }
  async function fsStravaExchangeCode(code) {
    return callStravaFunction("stravaExchangeCode", {
      code,
      redirectUri: stravaRedirectUri(),
    });
  }
  async function fsStravaGetConnection() {
    return callStravaFunction("stravaGetConnection");
  }
  async function fsStravaDisconnect() {
    return callStravaFunction("stravaDisconnect");
  }
  async function fsStravaSyncSession(session) {
    return callStravaFunction("stravaSyncSession", { session });
  }
  function stravaSportTypeForSession(session) {
    const name = String(session?.name || "").toLowerCase();
    const exercises = Array.isArray(session?.exercises) ? session.exercises : [];
    const cardioNames = exercises
      .filter((e) => e?.type === "cardio")
      .map((e) => String(e?.name || e?.muscle || "").toLowerCase())
      .join(" ");
    const haystack = `${name} ${cardioNames}`;
    if (/walk|walking/.test(haystack)) return "Walk";
    if (/run|running|jog/.test(haystack)) return "Run";
    if (/bike|bicycle|cycling|cycle/.test(haystack)) return "Ride";
    if (/row|rowing/.test(haystack)) return "Rowing";
    if (/elliptical/.test(haystack)) return "Elliptical";
    if (/stair/.test(haystack)) return "StairStepper";
    if (exercises.length && exercises.every((e) => e?.type === "cardio")) return "Workout";
    return "WeightTraining";
  }
  function buildStravaSessionPayload(session) {
    const exercises = (session?.exercises || []).map((ex) => ({
      id: ex.exId || ex.id || null,
      name: ex.name || "Exercise",
      type: ex.type || "strength",
      muscle: ex.muscle || null,
      group: ex.group || null,
      sets: (ex.sets || [])
        .filter((s) => s.done)
        .map((s) => ({
          reps: s.reps || 0,
          weight: s.weight || 0,
          duration: s.duration || 0,
          distance: s.distance || 0,
          calories: s.calories || 0,
          intensity: s.intensity || null,
        })),
    }));
    return {
      id: session?.id,
      name: session?.name || "Iron Body Workout",
      sportType: stravaSportTypeForSession(session),
      startTime: session?.startTime || Date.now(),
      endTime: session?.endTime || Date.now(),
      duration: Math.max(1, Math.round(Number(session?.duration || 0))),
      elapsedSeconds: Math.max(60, Math.round(Number(session?.duration || 0) * 60)),
      calories: session?.calories || null,
      intensity: session?.intensity || null,
      doneSets: session?.doneSets || 0,
      totalSets: session?.totalSets || 0,
      volume: sessionVol(session),
      exercises,
    };
  }

  async function fsRegisterPublicProfile(uid, name, photoURL, email) {
    return setDoc(doc(fbDb, "publicProfiles", uid), {
      uid, name: name || "", photoURL: photoURL || null, email: email || "",
      updatedAt: Date.now(),
    }, { merge: true }).catch(e => {
      console.warn("fsRegisterPublicProfile:", e.code, e.message);
    });
  }

  function fsListenPublicProfiles(cb) {
    return onSnapshot(
      collection(fbDb, "publicProfiles"),
      snap => cb(snap.docs.map(d => d.data())),
      err => { console.warn("fsListenPublicProfiles:", err.code, err.message); cb([]); }
    );
  }
  async function fsUpdateChangelog(id, text) {
    try {
      await setDoc(doc(fbDb, "changelog", id), { text }, { merge: true });
      return true;
    } catch (e) {
      console.error("fsUpdateChangelog:", e);
      return false;
    }
  }
  async function fsGetAllChangelog() {
    try {
      const snap = await getDocs(collection(fbDb, "changelog"));
      return snap.docs
        .map((d) => ({ id: d.id, ...d.data() }))
        .sort((a, b) => b.date - a.date);
    } catch (e) {
      console.error("fsGetAllChangelog:", e);
      return [];
    }
  }
  async function fsSaveChangelog(text, version) {
    try {
      const id = Date.now().toString(36);
      await setDoc(doc(fbDb, "changelog", id), {
        text,
        date: Date.now(),
        version: version || "1.1.1",
      });
      return true;
    } catch (e) {
      console.error("fsSaveChangelog:", e);
      return false;
    }
  }
  async function fsSendFeedback(uid, email, text, stars = 0) {
    try {
      const id = Date.now().toString(36) + Math.random().toString(36).slice(2);
      await setDoc(doc(fbDb, "feedback", id), {
        uid,
        email,
        text,
        stars,
        date: Date.now(),
        read: false,
      });
      return true;
    } catch (e) {
      console.error("fsSendFeedback:", e.code, e.message);
      return false;
    }
  }
  async function fsGetAllFeedback() {
    try {
      const snap = await getDocs(collection(fbDb, "feedback"));
      return snap.docs
        .map((d) => ({ id: d.id, ...d.data() }))
        .sort((a, b) => b.date - a.date);
    } catch (e) {
      console.error("fsGetAllFeedback:", e.code, e.message);
      return [];
    }
  }
  async function fsMarkFeedbackRead(uid, timestamp) {
    try {
      await setDoc(
        doc(fbDb, "users", uid, "data", "settings"),
        { lastReadFeedback: timestamp },
        { merge: true }
      );
    } catch (e) {
      console.error("fsMarkFeedbackRead:", e.code, e.message);
    }
  }
  async function fsGetMeasurements(uid) {
    try {
      const snap = await getDoc(doc(fbDb, "users", uid, "data", "measurements"));
      return snap.exists() ? (snap.data().list || []) : [];
    } catch (e) {
      if (e?.code !== "permission-denied") {
        console.error("fsGetMeasurements:", e.code, e.message);
      } else {
        console.warn("fsGetMeasurements: permission denied for uid", uid, "— check Firestore rules for coach access to users/{uid}/data/measurements");
      }
      return null; // null = failed (vs [] = exists but empty)
    }
  }
  async function fsSaveMeasurements(uid, list) {
    try {
      await setDoc(doc(fbDb, "users", uid, "data", "measurements"), {
        list: strip(list),
      });
    } catch (e) {
      console.error("fsSaveMeasurements:", e.code, e.message);
    }
  }
  /* ─── Firebase error helper ─────────────────────────────────────────────────── */
  function friendlyError(code) {
    switch (code) {
      case "auth/email-already-in-use":
        return "This email is already registered.";
      case "auth/invalid-email":
        return "Invalid email address.";
      case "auth/weak-password":
        return "Password must be at least 6 characters.";
      case "auth/user-not-found":
      case "auth/wrong-password":
      case "auth/invalid-credential":
        return "Invalid email or password.";
      case "auth/too-many-requests":
        return "Too many attempts. Try again later.";
      case "auth/requires-recent-login":
        return "Please log out and log back in to make this change.";
      default:
        return "Something went wrong. Please try again.";
    }
  }

